def monitor_context_length(query: str, retrieved_docs: list[str], max_tokens: int = 8000) -> dict:
    doc_tokens = sum(len(doc.split()) for doc in retrieved_docs)
    query_tokens = len(query.split())
    total_tokens = doc_tokens + query_tokens

    return {
        'total_tokens': total_tokens,
        'is_overflow': total_tokens > max_tokens,
        'overflow_by': max(0, total_tokens - max_tokens),
        'recommendation': 'truncate' if total_tokens > max_tokens else 'good'
    }

