def smart_truncate_context(query: str, docs: list[str], max_tokens: int = 6000) -> list[str]:
    if monitor_context_length(query, docs, max_tokens)['is_overflow']:
        # Score docs by relevance
        scores = [detect_retrieval_quality(query, [doc])['avg_similarity'] 
                 for doc in docs]

        # Keep top scoring docs until token limit
        sorted_docs = [doc for _, doc in sorted(zip(scores, docs), reverse=True)]
        truncated = []
        current_tokens = 0

        for doc in sorted_docs:
            doc_tokens = len(doc.split())
            if current_tokens + doc_tokens < max_tokens:
                truncated.append(doc)
                current_tokens += doc_tokens
            else:
                break

        return truncated
    return docs

# Use in RAG tool
def rag_tool(query):
    docs = retrieve_docs(query)
    return smart_truncate_context(query, docs)
